// Даты за последние 7 дней
const now = new Date();
const weekAgo = new Date();
weekAgo.setDate(now.getDate() - 7);

return [{
  json: {
    cutoff_timestamp: weekAgo.toISOString(),
    page: 1
  }
}];

// OmniDesk возвращает: {"0": {"case": {...}}, "1": {...}}
const response = $input.first().json;
const prevData = $('Set Date Range').first().json;
const cutoffDate = new Date(prevData.cutoff_timestamp);

// Проверка на ошибки
if (typeof response === 'string' || response.error) {
  throw new Error('API Error: ' + JSON.stringify(response));
}

// Конвертируем объект с числовыми ключами в массив
const keys = Object.keys(response).filter(k => !isNaN(parseInt(k)));
const tickets = [];

for (const key of keys) {
  const caseData = response[key].case || response[key];

  let createdAt;
  try {
    createdAt = new Date(caseData.created_at);
  } catch (e) {
    continue;
  }

  // Только за последние 7 дней
  if (createdAt >= cutoffDate) {
    tickets.push({
      ticket_id: caseData.case_id,
      created_at: caseData.created_at,
      closed_at: caseData.closed_at !== '-' ? caseData.closed_at : null,
      status: caseData.status,
      priority: caseData.priority,
      channel: caseData.channel,
      subject: caseData.subject,
      labels: caseData.labels || [],
      closing_speed: caseData.closing_speed !== '-' ? parseInt(caseData.closing_speed) : null
    });
  }
}

console.log(`Found ${tickets.length} tickets from last 7 days`);

return tickets.map(ticket => ({ json: ticket }));

const ticket = $('Loop Tickets').first().json;
const resp = $input.first().json;

// Parse date to ISO
function parseDate(dateStr) {
  if (!dateStr || dateStr === '-') return null;
  try { return new Date(dateStr).toISOString(); } catch { return null; }
}

// Strip HTML
function stripHtml(s) {
  if (!s) return null;
  return String(s)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 5000);
}

// Handle errors
if (resp?.error || resp?.statusCode === 403) {
  return [{
    json: {
      ticket_id: parseInt(ticket.ticket_id),
      created_at: parseDate(ticket.created_at),
      closed_at: parseDate(ticket.closed_at),
      status: ticket.status || null,
      priority: ticket.priority || null,
      channel: ticket.channel || null,
      subject: ticket.subject || null,
      first_message_text: null,
      labels: ticket.labels?.length > 0 ? ticket.labels : null,
      closing_speed: ticket.closing_speed ? parseInt(ticket.closing_speed) : null
    }
  }];
}

// Parse messages
const numKeys = Object.keys(resp || {}).filter(k => !isNaN(parseInt(k)));
const msgs = numKeys.map(k => resp[k]?.message || resp[k]).filter(Boolean);

// Get first customer message
const sortByDate = (a, b) => new Date(a.created_at) - new Date(b.created_at);
const customerMsgs = msgs.filter(m => !m.staff_id && !m.note).sort(sortByDate);
let first = customerMsgs[0] || msgs.sort(sortByDate)[0] || null;

let text = first ? (first.content || first.content_html || null) : null;

return [{
  json: {
    ticket_id: parseInt(ticket.ticket_id),
    created_at: parseDate(ticket.created_at),
    closed_at: parseDate(ticket.closed_at),
    status: ticket.status || null,
    priority: ticket.priority || null,
    channel: ticket.channel || null,
    subject: ticket.subject || null,
    first_message_text: stripHtml(text),
    labels: ticket.labels?.length > 0 ? ticket.labels : null,
    closing_speed: ticket.closing_speed ? parseInt(ticket.closing_speed) : null
  }
}];

const items = $input.first().json.data || [];
const count = items.length;

return [{
  json: {
    success: true,
    tickets_processed: count,
    timestamp: new Date().toISOString()
  }
}];
